from dataclasses import dataclass, field
from enum import Enum
from typing import Any, List, Dict, Optional
from datetime import datetime
import json
import random

# ========== CRICKET-THEMED AGENT STATE & LIFECYCLE ==========

class AgentPhase(Enum):
    INITIALIZED = "initialized"
    PLANNING = "planning"
    ACTION = "action"
    OBSERVATION = "observation"
    REFLECTION = "reflection"
    COMPLETED = "completed"
    FAILED = "failed"

@dataclass
class ToolCall:
    """Represents a single tool invocation in the agent's action."""
    tool_name: str
    parameters: Dict[str, Any]
    timestamp: datetime = field(default_factory=datetime.now)
    result: Optional[Any] = None
    error: Optional[str] = None
    retry_count: int = 0
    max_retries: int = 3

    def execute(self) -> bool:
        """Simulate tool execution with error handling."""
        try:
            # Simulate transient and permanent errors
            if random.random() < 0.1 and self.retry_count < self.max_retries:
                raise ConnectionError(f"Tool {self.tool_name} temporarily unavailable")

            # Simulate tool results
            if self.tool_name == "check_pitch_conditions":
                self.result = {"pitch_type": "good_length", "moisture": "moderate", "cracks": False}
            elif self.tool_name == "analyze_batsman":
                self.result = {"technique_weakness": "short_ball", "recent_form": "strong", "avg_vs_pace": 42.5}
            elif self.tool_name == "query_match_history":
                self.result = {"matches_vs_player": 12, "head_to_head": {"wickets": 4}, "economy": 7.2}
            elif self.tool_name == "request_review":
                self.result = {"review_outcome": random.choice(["out", "not_out", "umpires_call"]), "footage_clear": True}
            else:
                self.result = {"status": "success"}
            return True
        except ConnectionError as e:
            if self.retry_count < self.max_retries:
                self.retry_count += 1
                return self.execute()  # Exponential backoff pattern
            self.error = str(e)
            return False

@dataclass
class AgentState:
    """Manages agent's internal state and lifecycle."""
    agent_name: str
    current_phase: AgentPhase
    goal: str
    belief_state: Dict[str, Any] = field(default_factory=dict)
    action_history: List[ToolCall] = field(default_factory=list)
    observations: List[Dict[str, Any]] = field(default_factory=list)
